import { existsSync, readFileSync } from 'fs';
import { resolve, join, relative, sep, basename } from 'path';
import { getLearningVaultRoot, getLearningRoot } from './lib/config.mjs';
import { readFolder, readNote } from './lib/frontmatter.mjs';
import { buildFrontmatter, writeNote, today as todayString } from './lib/markdown.mjs';

const SCRIPTS_DIR = import.meta.dirname;
const VAULT_ROOT = resolve(SCRIPTS_DIR, '..');
const LEARNING_VAULT_ROOT = getLearningVaultRoot();
const LEARNING_ROOT = getLearningRoot();
const SESSIONS_DIR = join(LEARNING_ROOT, '04_Sessions');
const NODES_DIR = join(LEARNING_ROOT, '02_Nodes');
const CONNECTIONS_DIR = join(LEARNING_ROOT, '03_Connections');
const MASTERY_DIR = join(LEARNING_ROOT, '05_Mastery');
const TEMPLATES_DIR = join(LEARNING_ROOT, '06_Templates');
const PROJECTS_DIR = join(LEARNING_ROOT, '07_Projects');
const REVIEWS_DIR = join(LEARNING_ROOT, '08_Reviews');

export async function run(flags = {}) {
  const date = String(flags.date || todayString()).trim();
  const force = Boolean(flags.force);
  const weeklyReview = Boolean(flags['weekly-review']);
  const summary = { date, created: [], skipped: [], warnings: [] };

  // Session note (replaces old daily + check + wildcard)
  const sessionPath = join(SESSIONS_DIR, `${date}.md`);
  const sessionNote = await ensureSessionNote(sessionPath, date, force, summary);
  const sessionData = sessionNote?.data || {};

  const candidateNodes = toArray(sessionData.candidate_nodes || flags.nodes);
  const eventDomains = toArray(sessionData.event_domains);
  const sourceNotes = toArray(sessionData.source_notes);

  // Node stubs — created from --nodes "NodeA, NodeB, NodeC"
  const nodeNames = toArray(flags.nodes || '');
  for (const nodeName of nodeNames.slice(0, 4)) {
    const nodePath = join(NODES_DIR, `${sanitizeFilenameSegment(nodeName, { keepSpaces: true })}.md`);
    ensureNote(
      nodePath,
      buildNodeNote({ date, nodeName, sessionPath }),
      force,
      summary,
      `Node: ${nodeName}`
    );
  }

  // Connection stubs — created from --connections "NodeA->NodeB, NodeB->NodeC"
  const connectionPairs = toArray(flags.connections || '');
  for (const pair of connectionPairs.slice(0, 4)) {
    const [nodeA, nodeB] = pair.split('->').map(s => s.trim());
    if (!nodeA || !nodeB) continue;
    const connectionFilename = `${sanitizeFilenameSegment(nodeA)} → ${sanitizeFilenameSegment(nodeB)}`;
    const connectionPath = join(CONNECTIONS_DIR, `${connectionFilename}.md`);
    ensureNote(
      connectionPath,
      buildConnectionNote({ date, nodeA, nodeB, sessionPath }),
      force,
      summary,
      `Connection: ${nodeA} → ${nodeB}`
    );
  }

  // Optional project note
  const projectName = normalizeNullable(flags.project);
  let projectPath = null;
  if (projectName) {
    projectPath = join(PROJECTS_DIR, `${sanitizeFilenameSegment(projectName, { keepSpaces: true })}.md`);
    const topicId = normalizeNullable(flags['topic-id']);
    const masteryNote = topicId ? await findMasteryByTopicId(topicId) : null;
    ensureNote(
      projectPath,
      buildProjectNote({
        date,
        projectTitle: projectName,
        sessionPath,
        masteryNote,
        sourceNotes,
        eventDomains,
        candidateNodes,
      }),
      force,
      summary,
      'Project'
    );
  }

  if (weeklyReview) {
    const weeklyPath = join(REVIEWS_DIR, `${date} Weekly Review.md`);
    ensureNote(
      weeklyPath,
      buildWeeklyReviewNote({ date, projectPath, eventDomains }),
      force,
      summary,
      'Weekly review'
    );
  }

  printSummary(summary, { sessionPath, nodeNames, connectionPairs });
  return summary;
}

async function ensureSessionNote(filePath, date, force, summary) {
  if (!force && existsSync(filePath)) {
    summary.skipped.push(`Session note already exists: ${toVaultRelative(filePath)}`);
    return readNote(filePath);
  }

  const templatePath = join(TEMPLATES_DIR, 'Session.md');
  writeNote(filePath, materializeTemplate(templatePath, date));
  summary.created.push(`Session note: ${toVaultRelative(filePath)}`);
  return readNote(filePath);
}

function ensureNote(filePath, content, force, summary, label) {
  if (!force && existsSync(filePath)) {
    summary.skipped.push(`${label} already exists: ${toVaultRelative(filePath)}`);
    return false;
  }
  writeNote(filePath, content);
  summary.created.push(`${label}: ${toVaultRelative(filePath)}`);
  return true;
}

function buildNodeNote({ date, nodeName, sessionPath }) {
  const frontmatter = {
    template: 'node',
    note_type: 'learning',
    date_created: date,
    node_name: nodeName,
    primary_domain: '',
    connected_domains: [],
    mastery_level: 0,
    origin_session: wikiLink(sessionPath),
    connected_nodes: [],
    project_links: [],
    tags: ['learning-system', 'node'],
  };

  return [
    buildFrontmatter(frontmatter),
    '',
    `# Node: ${nodeName}`,
    '',
    `node_name:: ${nodeName}`,
    'primary_domain:: ',
    'connected_domains:: ',
    'mastery_level:: 0',
    `origin_session:: ${wikiLink(sessionPath)}`,
    '',
    '## Definition',
    '',
    '> ',
    '',
    '---',
    '',
    '## Core Mechanism',
    '',
    '',
    '---',
    '',
    '## Domains Involved',
    '',
    '- **Primary:**',
    '- **Secondary:**',
    '',
    '---',
    '',
    '## Why It Matters',
    '',
    '',
    '---',
    '',
    '## Example',
    '',
    '',
    '---',
    '',
    '## Connections',
    '',
    '| Node | Connection Type | Explanation |',
    '|------|----------------|-------------|',
    '| [[]] | | |',
    '',
    '---',
    '',
    '## Notes',
    '',
    '- ',
    '',
  ].join('\n');
}

function buildConnectionNote({ date, nodeA, nodeB, sessionPath }) {
  const frontmatter = {
    template: 'connection',
    note_type: 'learning',
    date_created: date,
    node_a: nodeA,
    node_b: nodeB,
    connection_type: '',
