    `node_b:: ${nodeB}`,
    'connection_type:: ',
    `origin_session:: ${wikiLink(sessionPath)}`,
    '',
    '## Connection Type',
    '',
    '> Cause · Dependency · Feedback Loop · Tradeoff · Reinforcement · Historical Analogy · Structural Similarity · Constraint · Incentive Relationship',
    '',
    '**Type:**',
    '',
    '---',
    '',
    '## Explanation',
    '',
    '',
    '---',
    '',
    '## Chain Context',
    '',
    '```',
    `... → ${nodeA} → ${nodeB} → ...`,
    '```',
    '',
    '---',
    '',
    '## Notes',
    '',
    '- ',
    '',
  ].join('\n');
}

function buildProjectNote({ date, projectTitle, sessionPath, masteryNote, sourceNotes, eventDomains, candidateNodes }) {
  const frontmatter = {
    template: 'depth_project',
    note_type: 'learning',
    date_created: date,
    project_status: 'queued',
    origin_sessions: [wikiLink(sessionPath)],
    connected_mastery: masteryNote ? [wikiLink(masteryNote.path)] : [],
    connected_systems: eventDomains.slice(0, 4),
    signals_to_track: candidateNodes.slice(0, 4),
    core_nodes: candidateNodes.slice(0, 3),
    node_cluster: [],
    connection_refs: [],
    domains_spanned: eventDomains.slice(0, 3),
