    'connection_refs:: ',
    `domains_spanned:: ${eventDomains.slice(0, 3).join(', ')}`,
    'progress_level:: 0',
    `last_updated:: ${date}`,
    '',
    '## Goal',
    '',
    `- Build a connected, explainable system around "${projectTitle}" across 3+ domains.`,
    '',
    '---',
    '',
    '## Why It Matters',
    '',
    '- This project exists because the node cluster is recurring, connected, and unresolved.',
    '',
    '---',
    '',
    '## Node Cluster',
    '',
    ...candidateNodes.slice(0, 3).map(item => `- ${item}`),
    ...(candidateNodes.length ? [] : ['- ']),
    '',
    '---',
    '',
    '## Key Connections',
    '',
    '- [[]] → [[]] | Type:',
    '',
    '---',
    '',
    '## Connected Systems',
    '',
    ...eventDomains.slice(0, 4).map(item => `- ${item}`),
