function buildWeeklyReviewNote({ date, projectPath, eventDomains }) {
  const macroCovered = eventDomains.includes('Inflation') || eventDomains.includes('Policy') || eventDomains.includes('Macro');
  const slowSectorCovered = eventDomains.includes('Food Systems') || eventDomains.includes('Supply Chains');
  const frontierCovered = eventDomains.includes('AI') || eventDomains.includes('Frontier');

  const frontmatter = {
    template: 'weekly_review',
    note_type: 'learning',
    review_date: date,
    week_number: '',
    nodes_created: 0,
    connections_created: 0,
    macro_covered: macroCovered,
    slow_sector_covered: slowSectorCovered,
    frontier_covered: frontierCovered,
    behavioral_covered: false,
    active_project: '',
    stale_areas: [],
    neglected_domains: [],
    blind_spots: [],
    priority_gaps: [],
    tags: ['learning-system', 'weekly-review'],
  };

  return [
    buildFrontmatter(frontmatter),
    '',
    `# Weekly Review — ${date}`,
    '',
    `review_date:: ${date}`,
    'week_number:: ',
    'nodes_created:: 0',
    'connections_created:: 0',
    `active_project:: ${projectPath ? wikiLink(projectPath) : ''}`,
    'stale_areas:: ',
    'neglected_domains:: ',
    'blind_spots:: ',
    'priority_gaps:: ',
    '',
    '## Graph This Week',
    '',
    '- **Nodes created:**',
    '- **Connections created:**',
    '- **Strongest nodes:**',
    '- **Weakest nodes:**',
    '',
    '---',
    '',
    '## Domain Coverage',
    '',
    '| Domain | Sessions Touched | Health |',
    '|--------|-----------------|--------|',
    '| | | |',
    '',
    '**Neglected domains:**',
    '- ',
    '',
    '---',
    '',
    '## Coverage Check',
    '',
    `- Macro: ${macroCovered ? 'yes' : 'no'}`,
    `- Slow sector: ${slowSectorCovered ? 'yes' : 'no'}`,
    `- Frontier topic: ${frontierCovered ? 'yes' : 'no'}`,
    '- Behavioral trend: no',
    '',
    '---',
    '',
    '## Blind Spots',
    '',
    '- ',
    '',
    '---',
    '',
    '## Project State',
    '',
    `- **Active project:** ${projectPath ? wikiLink(projectPath) : 'None'}`,
    '- **Queue health:**',
    '- **Promotion candidates:**',
    '- **On Hold:**',
    '',
    '---',
    '',
    '## Stale Areas',
    '',
    '- ',
    '',
    '---',
    '',
    '## Next Week Focus',
    '',
    '- Primary domain:',
    '- Node type to emphasize:',
    '- Anti-drift action:',
    '',
  ].join('\n');
}

function printSummary(summary, context) {
  console.log('\nLearning Session Scaffold');
  console.log('========================');
  console.log(`Date: ${summary.date}`);
  console.log(`Session note: ${toVaultRelative(context.sessionPath)}`);
  if (context.nodeNames?.length) console.log(`Node stubs: ${context.nodeNames.join(', ')}`);
  if (context.connectionPairs?.length) console.log(`Connection stubs: ${context.connectionPairs.join(', ')}`);

  if (summary.created.length) {
    console.log('\nCreated:');
    for (const item of summary.created) console.log(`  - ${item}`);
  }

  if (summary.skipped.length) {
    console.log('\nSkipped:');
    for (const item of summary.skipped) console.log(`  - ${item}`);
  }

  if (summary.warnings.length) {
    console.log('\nWarnings:');
    for (const item of summary.warnings) console.log(`  - ${item}`);
  }

  console.log('\nNext: open the session note, complete Steps 1–2, then build your nodes.');
}

function materializeTemplate(templatePath, date) {
  return readFileSync(templatePath, 'utf-8').replace(/\{\{date\}\}/g, date);
}

async function findMasteryByTopicId(topicId) {
  const notes = await readFolder(MASTERY_DIR, false);
  for (const note of notes) {
    if (String(note?.data?.topic_id || '').trim() !== topicId) continue;
    return {
      path: note.path,
      title: basename(note.filename, '.md'),
      data: note.data,
    };
  }
  return null;
}

function wikiLink(filePath) {
  return `[[${toVaultRelative(filePath).replace(/\.md$/i, '')}]]`;
}

function toVaultRelative(filePath) {
  if (filePath.startsWith(LEARNING_VAULT_ROOT)) {
    return relative(LEARNING_VAULT_ROOT, filePath).split(sep).join('/');
  }
  return relative(VAULT_ROOT, filePath).split(sep).join('/');
}

function toArray(value) {
  if (Array.isArray(value)) return value.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
  if (value === null || value === undefined) return [];
  const raw = String(value).trim();
  if (!raw) return [];
  return raw.split(',').map(part => part.trim()).filter(Boolean);
}

function normalizeNullable(value) {
  if (value === null || value === undefined) return null;
  const text = String(value).trim();
  return text || null;
}

function sanitizeFilenameSegment(value, options = {}) {
  const { keepSpaces = false } = options;
  const normalized = String(value)
    .replace(/[<>:"/\\|?*]+/g, ' ')
    .replace(/\s+/g, keepSpaces ? ' ' : '_')
    .replace(/_+/g, '_')
    .trim();
  return normalized || 'Untitled';
}

